    'CODE - Update interview_history',
  ];
  const rows = [input, ...names.map((n) => pickNodeJson(n)).filter(Boolean)];
  let merged = {};
  for (const row of rows) {
    merged = { ...merged, ...row };
    if (row.config && typeof row.config === 'object') {
      merged = { ...merged, ...row.config };
    }
  }
