        assessment_mode: 'live_speech',
        config: sessCfg,
        _session_patch_url: patchUrl,
        _session_patch_body: partialBody,
      },
    },
  ];
}

const techAvg =
  Number(session.technical_score) || computeTechnicalAverage(history, maxQ) || 0;
let speechAvg =
  norm.combined_speech_score != null && Number.isFinite(Number(norm.combined_speech_score))
    ? Math.round(Number(norm.combined_speech_score))
    : computeSpeechAverage(history, maxQ, speechPhases);

if (speechAvg == null) {
  const turnScores = turns
    .map((t) => Number(t.score))
    .filter((n) => Number.isFinite(n));
  speechAvg = turnScores.length
    ? Math.round(turnScores.reduce((a, b) => a + b, 0) / turnScores.length)
    : 0;
}

const combinedScore = Math.round(techAvg * techWeight + speechAvg * speechWeight);
const finalResult = combinedScore >= passThreshold ? 'PASS' : 'FAIL';
const lastPhase = maxQ + speechPhases;

const finalFeedback = [
  norm.final_feedback || norm.live_session_summary || '',
  `Technical: ${techAvg}/100 | Live communication: ${speechAvg}/100 | Combined: ${combinedScore}/100 (pass ${passThreshold}).`,
]
  .filter(Boolean)
  .join(' ');

const body = {
  interview_history: history,
  updated_at: iso,
  assessment_stage: 'completed',
  current_phase: lastPhase,
  status: 'completed',
  technical_score: techAvg,
  speech_score: speechAvg,
  score: combinedScore,
  result: finalResult,
  live_speech_audio_url: norm.session_audio_url || null,
  live_speech_duration_seconds: norm.duration_seconds || null,
  tab_switches: norm.tab_switches || 0,
};

const lastTurn = turns[turns.length - 1] || {};
const phaseScore = Math.round(Number(lastTurn.score ?? speechAvg));

// Overall soft skills = average of every voice turn's soft skills across the
// whole interview (not per-question). This is what the candidate and emails see.
const SOFT_SKILL_KEYS = [
  'communication_clarity',
  'fluency',
  'confidence',
  'professionalism',
  'english_proficiency',
  'answer_relevance',
];
const overallSoftSkills = (() => {
  const sums = {};
  const counts = {};
  for (const t of turns) {
    const s = t && typeof t.soft_skills === 'object' ? t.soft_skills : null;
    if (!s) continue;
    for (const k of SOFT_SKILL_KEYS) {
      const v = Number(s[k]);
      if (Number.isFinite(v)) {
        sums[k] = (sums[k] || 0) + v;
        counts[k] = (counts[k] || 0) + 1;
      }
    }
  }
  const out = {};
  let any = false;
  for (const k of SOFT_SKILL_KEYS) {
    if (counts[k]) {
      out[k] = Math.round(sums[k] / counts[k]);
      any = true;
    }
  }
  return any ? out : (lastTurn.soft_skills || null);
})();

return (async () => {
  let resolvedInterviewer = sessionInterviewer || sessCfg.interviewer_email || '';
  if (!resolvedInterviewer) {
    resolvedInterviewer = await lookupJobInterviewer(
      session.requisition_id || sessionCfg.requisition_id,
      sessionCfg.requisition_title || cfg.requisition_title,
      cfg.supabase_url || sessCfg.supabase_url,
      cfg.supabase_key || sessCfg.supabase_key
    );
    if (resolvedInterviewer) {
      sessCfg.interviewer_email = resolvedInterviewer;
    }
  }

  return [
    {
      json: {
        score: combinedScore,
        phase_score: phaseScore,
        soft_skills: overallSoftSkills,
        feedback: finalFeedback,
        nextQuestion: '',
        time_limit_seconds: null,
        deadline_at: null,
        complexity_tier: null,
        isFinal: true,
        assessment_mode: 'live_speech',
        speech_phases: speechPhases,
        result: finalResult,
        average_score: combinedScore,
        candidate_email: norm.candidate_email || session.candidate_email,
        session_id: session.id,
        requisition_id: session.requisition_id || sessionCfg.requisition_id || null,
        requisition_title: sessionCfg.requisition_title || cfg.requisition_title || null,
        interviewer_email: resolvedInterviewer,
        current_phase: lastPhase,
        config: sessCfg,
        gmail_thread_id: session.gmail_thread_id || null,
        gmail_message_id: session.gmail_message_id || null,
        mail_subject: session.mail_subject || null,
        _session_patch_url: patchUrl,
        _session_patch_body: body,
      },
    },
  ];
})();

